# -----------------------------------------------------------------------------
# 1. LORENZ SYSTEM & RUNGE-KUTTA 4 SOLVER
# -----------------------------------------------------------------------------

def lorenz_derivatives(state, sigma=10.0, rho=28.0, beta=8/3):
    """
    Compute time derivatives of the Lorenz system:
        dx/dt = sigma * (y - x)
        dy/dt = x * (rho - z) - y
        dz/dt = x * y - beta * z
    """
    x, y, z = state
    dx = sigma * (y - x)
    dy = x * (rho - z) - y
    dz = x * y - beta * z
    return np.array([dx, dy, dz])


def rk4_step(f, state, dt, **kwargs):
    """
    Advance one step using classical 4th-order Runge-Kutta.
    Achieves O(dt^5) local error -- critical for chaotic systems
    where errors grow exponentially.
    """
    k1 = f(state,              **kwargs)
    k2 = f(state + dt/2 * k1, **kwargs)
    k3 = f(state + dt/2 * k2, **kwargs)
    k4 = f(state + dt    * k3, **kwargs)
    return state + (dt / 6.0) * (k1 + 2*k2 + 2*k3 + k4)


def compute_trajectory(initial_state, dt=0.005, n_steps=20_000,
                        sigma=10.0, rho=28.0, beta=8/3):
    """
    Pre-compute the entire Lorenz trajectory before animating.
    Pre-computation ensures smooth, lag-free playback -- no ODE
    solving happens during the render loop.

    Returns
    -------
    trajectory : np.ndarray, shape (n_steps, 3)
    time_array : np.ndarray, shape (n_steps,)
    """
    trajectory = np.empty((n_steps, 3))
    trajectory[0] = np.asarray(initial_state, dtype=float)

    for i in range(1, n_steps):
        trajectory[i] = rk4_step(
            lorenz_derivatives,
            trajectory[i - 1],
            dt,
            sigma=sigma, rho=rho, beta=beta
        )

    time_array = np.arange(n_steps) * dt
    return trajectory, time_array


