# 2. COLOUR HELPERS
# -----------------------------------------------------------------------------

def make_trail_colors(trail_length, cmap_name='plasma'):
    """
    Build an (trail_length, 4) RGBA array that fades from nearly
    transparent at the tail to fully opaque at the head.
    Alpha ramps 0.05 -> 1.0 so older points appear ghostly.
    """
    cmap   = plt.get_cmap(cmap_name)
    t      = np.linspace(0, 1, trail_length)
    colors = cmap(t)
    colors[:, 3] = np.linspace(0.05, 1.0, trail_length)
    return colors


