def plot_full_attractor(traj, title='Lorenz Attractor - Full Trajectory'):
    """
    Render the complete trajectory as a static 3D line plot.
    Colour encodes time: early = purple, late = yellow (viridis).
    """
    print("Rendering static full-attractor plot ...")
    fig = plt.figure(figsize=(10, 8), facecolor='#0a0a0a')
    ax  = fig.add_subplot(111, projection='3d')
    ax.set_facecolor('#0a0a0a')
    ax.set_title(title, color='white', pad=15)

    n    = len(traj)
    cmap = plt.get_cmap('viridis')
    for i in range(0, n - 1, 50):
        end = min(i + 51, n)
        ax.plot(traj[i:end, 0], traj[i:end, 1], traj[i:end, 2],
                color=cmap(i / n), lw=0.4, alpha=0.8)

    ax.set_xlabel('X', color='grey')
    ax.set_ylabel('Y', color='grey')
    ax.set_zlabel('Z', color='grey')
    ax.tick_params(colors='#444444')
    for pane in (ax.xaxis.pane, ax.yaxis.pane, ax.zaxis.pane):
        pane.fill = False

    sm = plt.cm.ScalarMappable(cmap='viridis',
                                norm=plt.Normalize(vmin=0, vmax=n * 0.005))
    sm.set_array([])
    cbar = fig.colorbar(sm, ax=ax, shrink=0.5, pad=0.1)
    cbar.set_label('Time', color='white')
    cbar.ax.yaxis.set_tick_params(color='white')
    plt.setp(cbar.ax.yaxis.get_ticklabels(), color='white')

    plt.tight_layout()
    plt.show()
    print("Static plot closed.")


